    # Or just return the full description if it's short, or truncated.
    # Let's just return the full description for now, or maybe the first sentence.
    # Actually, the user asked for "list the company names please".
    # I will try to extract the name.
    
    desc = name
    # Heuristic extraction
    splitters = [" specializes", " is ", " operates", " provides", " focuses", " inc.", " corp.", " ltd.", " plc", " group", " holdings"]
    # Actually, "Inc.", "Corp" are part of the name.
    # Common verbs: "specializes", "is a", "provides", "operates", "focuses".
    verbs = [" specializes", " is ", " provides", " operates", " focuses", " engaged", " involved"]
    short_name = desc
    for v in verbs:
        if v in desc:
            short_name = desc.split(v)[0]
            break
        if v.upper() in desc: # Case sensitivity?
             short_name = desc.split(v.upper())[0]
             break
    
